lessons.solution:
fn get_first<'a>(s: &'a str) -> &'a str {
    let bytes = s.as_bytes();
    for (i, &item) in bytes.iter().enumerate() {
        if item == b' ' {
            return &s[0..i];
        }
    }
    &s[..]
}

fn main() {
    let text = String::from("Rust is safe");
    let word = get_first(&text);
    println!("First word: {}", word);
}

